const products = $input.all().map(i => i.json);

// Build category map — tries every common Magento column name
const getCategory = (p) => {
  return p.categories || p.category || p.product_categories ||
         p['Product Categories'] || p.Category || '';
};

const getBrand = (p) => {
  return p.manufacturer || p.brand || p.Brand || p.Manufacturer ||
         p['attribute_set_name'] || '';
};

const getTitle = (p) => {
  return p.name || p.title || p.product_name || p['Product Name'] || p.Name || '';
};

const map = {};

for (const p of products) {
  const raw = getCategory(p);
  // top level only — split by / or , or >
  const tops = raw.split(/[/,>]/).map(s => s.trim()).filter(Boolean);
  const top = tops[0] || 'Overig';

  if (!map[top]) {
    map[top] = { name: top, count: 0, total_len: 0, no_brand: 0, no_year: 0 };
  }
  const e = map[top];
  e.count++;
  const title = getTitle(p);
  e.total_len += title.length;
  const brand = getBrand(p);
  if (!brand || !title.toLowerCase().includes(brand.toLowerCase())) e.no_brand++;
  if (!/\d{4}/.test(title)) e.no_year++;
}

const categories = Object.values(map)
  .filter(c => c.count >= 1)
  .map(c => {
    const avg = c.count ? Math.round(c.total_len / c.count) : 0;
    const score = Math.min(100, Math.round(
      (c.no_brand / c.count) * 50 +
      (c.no_year  / c.count) * 30 +
      (avg < 25 ? 20 : 0)
    ));
    return {
      name: c.name,
      count: c.count,
      avg_title_length: avg,
      missing_brand: c.no_brand,
      missing_year: c.no_year,
      score
    };
  })
  .sort((a, b) => b.score - a.score);

return [{ json: { categories, total_products: products.length } }];

const category = $('Webhook').first().json.body.category || '';
const products = $input.all().map(i => i.json);

const getCategory = (p) => p.categories || p.category || p.product_categories || p['Product Categories'] || p.Category || '';
const getBrand    = (p) => p.manufacturer || p.brand || p.Brand || p.Manufacturer || p.attribute_set_name || '';
const getTitle    = (p) => p.name || p.title || p.product_name || p['Product Name'] || p.Name || '';
const getSku      = (p) => p.sku || p.SKU || p['Product SKU'] || p.product_sku || '';

const filtered = products.filter(p => {
  if (!category) return true;
  const cat = getCategory(p).toLowerCase();
  return cat.includes(category.toLowerCase());
});

const rows = filtered.map(p => {
  const sku = getSku(p);
  const original = getTitle(p);
  const brand = getBrand(p);

  // Build improved title:
  // 1. Prepend brand if not already there
  // 2. Trim to 70 chars max (Google Shopping limit)
  let improved = original;
  if (brand && !improved.toLowerCase().startsWith(brand.toLowerCase())) {
    improved = brand + ' ' + improved;
  }
  if (improved.length > 70) improved = improved.substring(0, 70).trimEnd();

  return '"' + sku.replace(/"/g,'""') + '","' +
         original.replace(/"/g,'""') + '","' +
         improved.replace(/"/g,'""') + '"';
});

const csv = 'sku,current_title,improved_title\n' + rows.join('\n');
const filename = (category || 'all').toLowerCase().replace(/[^a-z0-9]/g,'_') + '_titles.csv';

return [{
  json: {
    content: csv,
    filename,
    row_count: filtered.length,
    category: category || 'all'
  }
}];

const category = $('Webhook').first().json.body.category || '';
const products = $input.all().map(i => i.json);

const getCategory = (p) => p.categories || p.category || p.product_categories || p['Product Categories'] || p.Category || '';
const getBrand    = (p) => p.manufacturer || p.brand || p.Brand || p.Manufacturer || p.attribute_set_name || '';
const getTitle    = (p) => p.name || p.title || p.product_name || p['Product Name'] || p.Name || '';

const filtered = products.filter(p => {
  if (!category) return true;
  return getCategory(p).toLowerCase().includes(category.toLowerCase());
});

// Collect unique brands in this category
const brands = [...new Set(
  filtered.map(p => getBrand(p)).filter(Boolean)
)].sort();

const avgLen = filtered.length
  ? Math.round(filtered.reduce((s,p) => s + getTitle(p).length, 0) / filtered.length)
  : 0;

// Count how many products already have brand in title
const withBrand = filtered.filter(p => {
  const b = getBrand(p);
  const t = getTitle(p).toLowerCase();
  return b && t.includes(b.toLowerCase());
}).length;

const pctMissingBrand = filtered.length
  ? Math.round((1 - withBrand / filtered.length) * 100)
  : 0;

const rules = {
  meta: {
    generated_at: new Date().toISOString(),
    category: category || 'all categories',
    product_count: filtered.length,
    avg_title_length: avgLen,
    pct_missing_brand: pctMissingBrand,
    unique_brands: brands.length,
    brands: brands.slice(0, 30)
  },
  channable_rules: [
    {
      id: 1,
      name: 'Prepend brand to title if missing',
      description: `Applies to ${pctMissingBrand}% of products in this category`,
      condition: {
        AND: [
          { field: 'categories', operator: 'contains', value: category || '' },
          { field: 'brand',      operator: 'is not empty' },
          { field: 'title',      operator: 'does not contain', value: '[brand]' }
        ]
      },
      action: {
        field: 'title',
        transformation: 'set',
        value: '[brand] [title]'
      }
    },
    {
      id: 2,
      name: 'Truncate title to 70 characters',
      description: 'Google Shopping title limit — prevents truncation in ads',
      condition: {
        AND: [
          { field: 'categories', operator: 'contains', value: category || '' },
          { field: 'title',      operator: 'length greater than', value: 70 }
        ]
      },
      action: {
        field: 'title',
        transformation: 'truncate',
        value: 70
      }
    },
    {
      id: 3,
      name: 'Remove double spaces in title',
      description: 'Cleans up titles after brand prepend',
      condition: {
        AND: [
          { field: 'categories', operator: 'contains', value: category || '' },
          { field: 'title',      operator: 'contains', value: '  ' }
        ]
      },
      action: {
        field: 'title',
        transformation: 'replace',
        find: '  ',
        replace_with: ' '
      }
    }
  ]
};

const filename = 'channable_rules_' +
  (category || 'all').toLowerCase().replace(/[^a-z0-9]/g,'_') + '.json';

return [{
  json: {
    content: JSON.stringify(rules, null, 2),
    filename,
    row_count: filtered.length,
    category: category || 'all'
  }
}];
